MAP
  NAME                      "water"
  INCLUDE                   "header.inc"
  EXTENT                    487000 6820000 558000 6870000
  PROJECTION
    "init=epsg:3857"
  END
  WEB
    METADATA
      "team" "MOBI"
      "ows_title"           "Water"
      "ows_abstract"        "Water gerelateerde kaartlagen in de Gemeente Amsterdam"
      #"ows_onlineresource"  "MAP_URL_REPLACE/maps/water"

    END


  END
  OUTPUTFORMAT
    NAME "mvt"
    DRIVER MVT
    FORMATOPTION "EDGE_BUFFER=20"
  END  
  #==============================================================================================

  LAYER
    NAME                    "binnenwater"
    GROUP                   "water"
    INCLUDE                 "connection/dataservices.inc"
    PROCESSING              "CLOSE_CONNECTION=DEFER"
    PROCESSING              "LABEL_NO_CLIP=ON"
    DATA                    "geometry FROM (SELECT id, ST_Transform(geometry, 3857) AS geometry FROM public.water_binnenwater_v3) AS subquery USING srid=3857 USING UNIQUE id"
    TYPE                    POLYGON
    TEMPLATE                "empty"
    PROJECTION
      "init=epsg:3857"
    END

    METADATA
      "ows_title"           "Binnenwater"
      "ows_abstract"        "Dataset die weergeeft binnen welk gebied in Amsterdam men binnenhavengeldplichtig is."
      "wms_group_title"     "Water"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "multipolygon"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END

    CLASS
      NAME                  "binnenwater"
      TITLE                 "Binnenwater"
      STYLE
        ANTIALIAS           true
        COLOR               "#4c8fbc"
        OPACITY             20
      END
      STYLE
        OUTLINECOLOR        "#4c8fbc"
        WIDTH               2
      END
    END
  END

  LAYER
    NAME                    "uitstootvrije_zone_pleziervaart"
    GROUP                   "water"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "geometry FROM public.water_uitstootvrije_zone_pleziervaar_v1 USING srid=28992 USING UNIQUE id"
    TYPE                    POLYGON
    TEMPLATE                "empty"
    PROJECTION
      "init=epsg:28992"
    END

    METADATA
      "ows_title"           "Uitstootvrije zone pleziervaart"
      "ows_abstract"        "Dataset die weergeeft binnen welk gebied in Amsterdam een uitstootvrije zone is."
      "wms_group_title"     "Water"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "multipolygon"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END

    CLASS
      NAME                  "uitstootvrije_zone_pleziervaart"
      TITLE                 "Uitstootvrije zone pleziervaart"
      STYLE
        ANTIALIAS           true
        COLOR               "#FFA500"
        OPACITY             20
      END
      STYLE
        OUTLINECOLOR        "#FFA500"
        WIDTH               2
      END
    END
  END

END
